const profileRows = $('Read Profile').all().map(i => i.json);
const profile = profileRows.find(r => r.chat_id) || null;
if (!profile) return [];

const chat_id = profile.chat_id;
const interval = Number(profile.training_days_interval) || 1;
const weight = Number(profile.weight_kg) || 76;
const bmr = Number(profile.bmr) || 1600;
const baseline = Number(profile.daily_baseline_kcal) || 280;
const targetProtein = Number(profile.target_protein_g) || 0;
const targetKcal = Number(profile.target_kcal) || 0;
const goal = String(profile.goal || 'maintain').toLowerCase();
const goalMult = ({ lose: 0.8, maintain: 1.0, gain: 1.15 })[goal] || 1.0;

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const y = new Date(now); y.setDate(y.getDate() - 1);
const yest = `${y.getFullYear()}-${pad(y.getMonth()+1)}-${pad(y.getDate())}`;

// --- Workout blocks state ---
const blocksStateRows = $('Read Workout Blocks').all().map(i => i.json);
const blocksState = {};
for (const r of blocksStateRows) {
  const n = Number(r.block_num);
  if (!n) continue;
  blocksState[n] = { label: r.label || `№${n}`, active: String(r.active).toUpperCase() === 'TRUE' };
}
if (!Object.keys(blocksState).length) {
  for (const n of [1,2,3,4]) blocksState[n] = { label: `№${n}`, active: true };
}
const activeNums = Object.keys(blocksState).map(Number)
  .filter(n => blocksState[n].active).sort((a,b)=>a-b);
function nextActiveAfter(lastN, active) {
  if (!active.length) return null;
  const after = active.find(n => n > lastN);
  return after != null ? after : active[0];
}

// --- Last workout / cycle ---
const workoutRows = $('Read Workout Log').all().map(i => i.json);
const sortedW = workoutRows.filter(r => r.date).sort((a, b) => String(a.date).localeCompare(String(b.date)));
const lastWorkout = sortedW[sortedW.length - 1] || null;

function parseN(plan) {
  if (!plan) return null;
  const m = String(plan).match(/№?\s*([1-4])/);
  if (m) return Number(m[1]);
  const s = String(plan).toLowerCase();
  if (s.includes('грудь') && s.includes('бицепс')) return 1;
  if (s.includes('плечи') && s.includes('грудь'))  return 2;
  if (s.includes('спина') && s.includes('трицепс'))return 3;
  if (s.includes('ноги')) return 4;
  return null;
}

let expectedNum;
let isWorkoutDay;
if (!activeNums.length) {
  expectedNum = null;
  isWorkoutDay = false;
} else if (!lastWorkout) {
  expectedNum = activeNums[0];
  isWorkoutDay = true;
} else {
  const lastDate = new Date(String(lastWorkout.date));
  const todayD = new Date(today);
  const daysSince = Math.floor((todayD - lastDate) / 86400000);
  expectedNum = nextActiveAfter(parseN(lastWorkout.day_plan) || 0, activeNums);
  isWorkoutDay = daysSince >= interval;
}
const labels = Object.fromEntries(Object.entries(blocksState).map(([k,v]) => [k, v.label]));

// --- Расход тренировки ---
const wkRows = $('Read Workouts Catalog').all().map(i => i.json);
let workoutKcal = 0;
const exerciseLines = [];
if (expectedNum) {
  for (const r of wkRows) {
    if (Number(r.block_num) !== expectedNum) continue;
    if (!r.exercise) continue;
    const m = Number(r.met) || 0;
    const dm = Number(r.default_min) || 0;
    if (m && dm) workoutKcal += m * weight * dm / 60;
    const w = r.weight && r.weight !== '—' ? `, ${r.weight}` : '';
    exerciseLines.push(`- ${r.group}: ${r.exercise}, ${r.sets}×${r.reps}${w}`);
  }
}
workoutKcal = Math.round(workoutKcal);

// --- Вчерашние факты (для капрала есть что вспомнить) ---
const yestFood = $('Read Food Log').all().map(i => i.json).filter(r => String(r.date) === yest);
const yestSum = yestFood.reduce((a, r) => ({
  kcal: a.kcal + (Number(r.kcal) || 0),
  protein: a.protein + (Number(r.protein) || 0),
}), { kcal: 0, protein: 0 });
yestSum.kcal = Math.round(yestSum.kcal);
yestSum.protein = Math.round(yestSum.protein);
const yestWalk = $('Read Walking Log').all().map(i => i.json).filter(r => String(r.date) === yest);
const yestWalkMin = yestWalk.reduce((s, r) => s + (Number(r.duration_min) || 0), 0);
const yestWorkoutDone = workoutRows.some(r => String(r.date) === yest);

// --- Тренировка пропущена давно ---
let missedNote = '';
if (lastWorkout) {
  const lwd = new Date(String(lastWorkout.date) + 'T00:00:00');
  const today0 = new Date(today + 'T00:00:00');
  const daysSinceLast = Math.floor((today0 - lwd) / 86400000);
  if (daysSinceLast >= interval + 2) missedNote = `Последняя трен — ${daysSinceLast} дн назад. Интервал ${interval}. Не отлынивай.`;
}

// --- Вердикт по вчерашнему дню (капральский) ---
const yestVerdict = [];
if (yestFood.length === 0) {
  yestVerdict.push('Вчера в food_log пусто. Либо вообще не ел (сомневаюсь), либо забил.');
} else {
  if (targetKcal) {
    const diff = yestSum.kcal - targetKcal;
    if (diff > 200) yestVerdict.push(`Вчера ${yestSum.kcal} ккал — перебор на ${diff}.`);
    else if (diff < -300) yestVerdict.push(`Вчера ${yestSum.kcal} ккал — недоел ${-diff}. Жёсткий дефицит не нужен.`);
    else yestVerdict.push(`Вчера в бюджете: ${yestSum.kcal} из ${targetKcal} ккал.`);
  }
  if (targetProtein) {
    const protDiff = yestSum.protein - targetProtein;
    if (protDiff < -20) yestVerdict.push(`Белка добрал ${yestSum.protein} из ${targetProtein}г — недобор ${-protDiff}.`);
    else if (protDiff >= 0) yestVerdict.push(`Белок в норме (${yestSum.protein}г).`);
  }
}
if (yestWalkMin >= 30) yestVerdict.push(`Ходьба ${yestWalkMin} мин — норм.`);

// --- Сборка сообщения ---
let text;
const expectedExpense = bmr + baseline + (isWorkoutDay ? workoutKcal : 0);
const expectedTarget = Math.round(expectedExpense * goalMult);

const headlines = isWorkoutDay
  ? [`🌅 Утро. Сегодня ${labels[expectedNum]}.`, `🌅 Подъём. План на день: ${labels[expectedNum]}.`, `🌅 Доброе утро. День тренировки — ${labels[expectedNum]}.`]
  : [`🌅 Утро. День отдыха.`, `🌅 Подъём. Сегодня без зала — добирай ходьбой.`, `🌅 Доброе утро. Отдых, но не лежать.`];
const headline = headlines[now.getDate() % headlines.length];

const parts = [headline, ''];
if (yestVerdict.length) {
  parts.push(`📋 Итог вчера:`);
  for (const v of yestVerdict) parts.push(`- ${v}`);
  parts.push('');
}
if (missedNote) { parts.push(missedNote); parts.push(''); }

parts.push(`🎯 Сегодня бюджет ~${expectedTarget} ккал, белок ${targetProtein}г.`);
if (isWorkoutDay) {
  parts.push(`💪 ${labels[expectedNum]} (расход ~${workoutKcal} ккал):`);
  for (const l of exerciseLines) parts.push(l);
  parts.push('');
  parts.push(`Жду отчёт после трена. Без отчёта считаю что не было.`);
} else {
  parts.push(`💡 30 мин ходьбы (3.5 км/ч) = ~107 ккал. 90 мин = ~320. Используй.`);
}
text = parts.join('\n');

return [{ json: { chat_id, text } }];
